export const ICON_CATEGORIES = [
    "Zbraně",
    "Brnění",
    "Magie",
    "Bytosti",
    "Prostředí",
    "Předměty",
    "Hudba",
    "Příroda",
    "Ostatní",
] as const;

export type IconCategory = (typeof ICON_CATEGORIES)[number];

export function getIconByName(name: string): GameIconMeta | undefined {
    return GAME_ICONS.find((icon) => icon.name === name);
}
